class VerifyRequest(BaseModel):
    nonce_id: str
    signature: str


class VerifyResponse(BaseModel):
    address: str
    session_token: str
    expires_at: int


class MeResponse(BaseModel):
    address: str
    session_expires_at: int


def get_session_from_request(request: Request) -> Tuple[str, sqlite3.Row]:
    token = request.cookies.get(COOKIE_NAME) or request.headers.get("Authorization", "")
    if token.startswith("Bearer "):
        token = token[len("Bearer ") :].strip()

    session_id = verify_session_token(token)
    if not session_id:
        raise HTTPException(status_code=401, detail="Not authenticated")

    sess = get_session(session_id)
    if not sess:
        raise HTTPException(status_code=401, detail="Invalid session")
    if sess["revoked"]:
        raise HTTPException(status_code=401, detail="Session revoked")
    if sess["expires_at"] < now_ts():
        raise HTTPException(status_code=401, detail="Session expired")
    return session_id, sess


@app.middleware("http")
async def security_headers(request: Request, call_next):
    response = await call_next(request)
    response.headers["Cache-Control"] = "no-store"
    response.headers["X-Content-Type-Options"] = "nosniff"
    response.headers["X-Frame-Options"] = "DENY"
    response.headers["Referrer-Policy"] = "no-referrer"
    return response


@app.exception_handler(HTTPException)
async def http_exception_handler(request: Request, exc: HTTPException):
    return JSONResponse(status_code=exc.status_code, content={"error": exc.detail})


@app.post("/auth/nonce", response_model=NonceResponse)
def auth_nonce(req: NonceRequest):
    purge_expired()
    data = create_nonce(req.address, req.statement)
    return NonceResponse(
        nonce_id=data["nonce_id"],
        address=data["address"],
        message=data["message"],
        expires_at=data["expires_at"],
    )


@app.post("/auth/verify", response_model=VerifyResponse)
def auth_verify(req: VerifyRequest):
    purge_expired()
    row = get_nonce_record(req.nonce_id)

    if row["used"]:
        raise HTTPException(status_code=400, detail="Nonce already used")
    if row["expires_at"] < now_ts():
        raise HTTPException(status_code=400, detail="Nonce expired")

    issued_at = int(row["issued_at"])
    if abs(now_ts() - issued_at) > (NONCE_TTL_SECONDS + ALLOWED_CLOCK_SKEW_SECONDS):
        raise HTTPException(status_code=400, detail="Stale nonce")

    address = normalize_address(row["address"])
    message = build_login_message(address, row["nonce"], issued_at, statement=row["statement"])

    recovered = recover_address_from_signature(message, req.signature)
    if Web3.to_checksum_address(recovered) != Web3.to_checksum_address(address):
        raise HTTPException(status_code=401, detail="Signature does not match address")

    mark_nonce_used(req.nonce_id)

    session_id, sess_expires = create_session(address)
    token = make_session_token(session_id)

    resp = JSONResponse(
        status_code=200,
        content=VerifyResponse(address=address, session_token=token, expires_at=sess_expires).model_dump(),
    )
    resp.set_cookie(
        key=COOKIE_NAME,
        value=token,
        max_age=SESSION_TTL_SECONDS,
        expires=SESSION_TTL_SECONDS,
        httponly=True,
        secure=bool(os.getenv("COOKIE_SECURE", "0") == "1"),
        samesite=os.getenv("COOKIE_SAMESITE", "lax"),
        path="/",
    )
    return resp


@app.get("/auth/me", response_model=MeResponse)
def auth_me(dep=Depends(get_session_from_request)):
    _, sess = dep
    return MeResponse(address=sess["address"], session_expires_at=int(sess["expires_at"]))


@app.post("/auth/logout")
def auth_logout(dep=Depends(get_session_from_request)):
    session_id, _ = dep
    revoke_session(session_id)
    resp = JSONResponse(status_code=200, content={"ok": True})
    resp.delete_cookie(COOKIE_NAME, path="/")
    return resp


